        let ele = this.a[this.top];
        console.log("Peeked: " + ele);
        return ele;
    } else {
        console.log("Stack is empty. Cannot peek.");
        return -1;
    }
}

Stack.prototype.isEmpty = function() {
    return this.top === -1;
}

